SELECT id, name, path, component, icon, order_index, parent_id, type, external_url, target, status
FROM menus
WHERE id = #{id}

SELECT DISTINCT m.id, m.name, m.path, m.component, m.icon, m.order_index, m.parent_id, m.type, m.external_url, m.target, m.status
FROM menus m
WHERE m.id IN

    #{id}

AND m.status = #{status}
ORDER BY m.order_index ASC
